function reddUp(edfFile, fileName)%% closes screens, shuts down eyelink, clears working memory% % by Martin Rolfs% re-enable keyboardListenChar(1);if isempty(edfFile) == 0    closeFileStatus = Eyelink('CloseFile');    if closeFileStatus ~= 0        fprintf('WARNING: Problem saving EDF file!');    end    try        Eyelink('ReceiveFile', edfFile, strcat(fileName(1:end-4), datestr(now,'yyyymmdd-HHMM'),'.edf'));    catch %#ok<CTCH>        fprintf('WARNING: Problem receiving EDF file!\n');    end    Eyelink('ShutDown');end% Screens schliessenShowCursor;% Screen(visual.main,'Resolution', scr.oldRes);Screen('CloseAll');% Speicher aufraumenclear mex;clear fun;home;